// Extract the CHARTS_JSON block from the AI output and split into one item per chart
const aiOutput = $input.first().json.output || '';

// Parse the JSON block between [CHARTS_JSON] and [/CHARTS_JSON] tags
const match = aiOutput.match(/\[CHARTS_JSON\]([\s\S]*?)\[\/CHARTS_JSON\]/);

if (!match) {
  // Fallback: return error item so the workflow doesn't silently stop
  return [{ json: { error: 'No CHARTS_JSON block found in AI output', rawOutput: aiOutput.slice(0, 500) } }];
}

let charts;
try {
  charts = JSON.parse(match[1].trim());
} catch (e) {
  return [{ json: { error: 'Failed to parse CHARTS_JSON: ' + e.message, rawJson: match[1].slice(0, 500) } }];
}

if (!Array.isArray(charts) || charts.length === 0) {
  return [{ json: { error: 'CHARTS_JSON is empty or not an array' } }];
}

// Return one item per chart — each item carries sheetName + chartConfig
return charts
  .filter(c => c.chartConfig)
  .map(c => ({ json: { sheetName: c.sheetName || 'chart', chartConfig: c.chartConfig } }));

// Rename binary field chartImage → data (required by Google Drive)
// Recover sheetName from the upstream Parse AI Chart Configs node (paired item)
const sheetName = $('Parse AI Chart Configs').item.json.sheetName || 'chart';
const item = $input.first();
const binary = { data: item.binary.chartImage };
return [{ json: { sheetName }, binary }];
